import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    """
    {This algorithm selects the next customer based on a dynamic weighting scheme that integrates adaptive learning 
    from historical truck wait times, proximity to time window thresholds, and balanced network dispersion to optimize route efficiency and minimize delays.}
    """
    def euclidean_distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    def harmonic_mean(x, y):
        return (2 * x * y) / (x + y) if (x + y) != 0 else 0

    best_node = None
    min_harmonic_penalty = float('inf')

    for i, customer in enumerate(unvisited_customers):
        distance_to_customer = euclidean_distance(cur_truck_pos, customer)
        arrival_time = current_time + (distance_to_customer / truck_speed)

        if arrival_time > time_windows[i][1]:
            continue

        waiting_time = max(0, time_windows[i][0] - arrival_time)
        proximity_weight = time_windows[i][1] - arrival_time
        dispersion_penalty = sum(euclidean_distance(customer, pos) < distance_to_customer for pos in all_truck_pos)

        harmonic_penalty = harmonic_mean(distance_to_customer + waiting_time, proximity_weight) + dispersion_penalty

        if harmonic_penalty < min_harmonic_penalty:
            min_harmonic_penalty = harmonic_penalty
            best_node = i

    if best_node is None:
        best_node = 'None'

    return best_node
